"use client";

import {
  type AccordionMultipleProps,
  type AccordionProps,
  Accordion as AccordionRoot,
  type AccordionSingleProps,
} from "./accordion";
import { AccordionContent, type AccordionContentProps } from "./accordion-content";
import { AccordionHeader, type AccordionHeaderProps } from "./accordion-header";
import { AccordionItem, type AccordionItemProps } from "./accordion-item";
import {
  AccordionTrigger,
  type AccordionTriggerProps,
  type AccordionTriggerVariantProps,
  accordionTriggerVariants,
} from "./accordion-trigger";

/**
 * Collapsible content sections with single or multiple open items. Supports controlled and
 * uncontrolled modes.
 */
const Accordion = Object.assign(AccordionRoot, {
  Header: AccordionHeader,
  Item: AccordionItem,
  Trigger: AccordionTrigger,
  Content: AccordionContent,
});

export { Accordion, type AccordionProps, type AccordionSingleProps, type AccordionMultipleProps };
export { AccordionHeader, type AccordionHeaderProps };
export { AccordionItem, type AccordionItemProps };
export {
  AccordionTrigger,
  accordionTriggerVariants,
  type AccordionTriggerProps,
  type AccordionTriggerVariantProps,
};
export { AccordionContent, type AccordionContentProps };

"use client";

import { getNavigationItems } from "@/hooks/utils/navigation-items";
import { type KeyboardEvent as ReactKeyboardEvent, useMemo, useRef } from "react";
import { useComposedRefs } from "@/hooks/use-composed-refs";
import { cn } from "@/lib/utils";
import { AccordionContext } from "./accordion-context";
import { type AccordionProps, useAccordionState } from "./use-state";

export type {
  AccordionMultipleProps,
  AccordionProps,
  AccordionSingleProps,
} from "./use-state";

const ACCORDION_ROOT_ATTRIBUTE = "data-diffgazer-accordion-root";

function getNavigableTriggers(container: HTMLElement | null): HTMLElement[] {
  // Use skipDisabled: false because aria-disabled non-collapsible triggers
  // remain in the roving tab order per APG. Filter explicit HTML/data-disabled
  // ourselves.
  return getNavigationItems(container, {
    type: "button",
    skipDisabled: false,
    ownerSelector: `[${ACCORDION_ROOT_ATTRIBUTE}]`,
  }).filter((trigger) => {
    const View = trigger.ownerDocument.defaultView;
    if (trigger.dataset.disabled !== undefined) return false;
    if (View && trigger instanceof View.HTMLButtonElement && trigger.disabled) return false;
    return true;
  });
}

function containsActiveElement(el: HTMLElement): boolean {
  const activeElement = el.ownerDocument.activeElement;
  const View = el.ownerDocument.defaultView;
  return Boolean(View && activeElement instanceof View.HTMLElement && el.contains(activeElement));
}

/**
 * Collapsible content sections with single or multiple open items. Supports controlled and
 * uncontrolled modes.
 */
function AccordionRoot(props: AccordionProps) {
  const {
    ref,
    onKeyDown: externalOnKeyDown,
    "aria-label": ariaLabel,
    "aria-labelledby": ariaLabelledBy,
  } = props;
  const { openValues, onToggle, collapsible } = useAccordionState(props);
  const containerRef = useRef<HTMLDivElement>(null);
  const composedRef = useComposedRefs(containerRef, ref);

  const focusTrigger = (index: number) => {
    const triggers = getNavigableTriggers(containerRef.current);
    const trigger = triggers[index];
    if (!trigger) return;

    trigger.scrollIntoView?.({ block: "nearest" });
    trigger.focus();
  };

  const handleKeyDown = (e: ReactKeyboardEvent) => {
    externalOnKeyDown?.(e);
    if (e.defaultPrevented) return;

    const triggers = getNavigableTriggers(containerRef.current);
    if (triggers.length === 0) return;

    const currentIndex = triggers.findIndex(containsActiveElement);
    if (currentIndex < 0) return;

    switch (e.key) {
      case "ArrowUp":
        focusTrigger(currentIndex <= 0 ? triggers.length - 1 : currentIndex - 1);
        e.preventDefault();
        break;
      case "ArrowDown":
        focusTrigger(currentIndex >= triggers.length - 1 ? 0 : currentIndex + 1);
        e.preventDefault();
        break;
      case "Home":
        focusTrigger(0);
        e.preventDefault();
        break;
      case "End":
        focusTrigger(triggers.length - 1);
        e.preventDefault();
        break;
    }
  };

  const contextValue = useMemo(
    () => ({ value: openValues, onToggle, collapsible }),
    [openValues, onToggle, collapsible],
  );

  return (
    <AccordionContext value={contextValue}>
      {/* biome-ignore lint/a11y/useSemanticElements: role="group" labels the related set of accordion panels; <fieldset> is for form controls and is not appropriate here. */}
      <div
        ref={composedRef}
        role="group"
        data-slot="accordion"
        aria-label={ariaLabel}
        aria-labelledby={ariaLabelledBy}
        className={cn("divide-y divide-border", props.className)}
        onKeyDown={handleKeyDown}
        {...{ [ACCORDION_ROOT_ATTRIBUTE]: "" }}
      >
        {props.children}
      </div>
    </AccordionContext>
  );
}

export { AccordionRoot as Accordion };

"use client";

import { createContext, useContext } from "react";

/** Context value shared by accordion. */
export interface AccordionContextValue {
  /** Controlled open value(s). string for single mode, string[] for multiple. */
  value: string[];
  /** Called when an item should toggle. */
  onToggle: (itemValue: string) => void;
  /** Single mode only. When false, the currently open item cannot be closed by clicking it. */
  collapsible: boolean;
}

/**
 * Set by AccordionHeader so a trigger composed inside it skips its own default
 * heading wrapper, avoiding a doubled heading in the accessibility tree.
 */
export const AccordionHeaderContext = createContext(false);

/** Provides accordion header present behavior. */
export function useAccordionHeaderPresent() {
  return useContext(AccordionHeaderContext);
}

/** React context backing accordion. */
export const AccordionContext = createContext<AccordionContextValue | undefined>(undefined);

/** Reads the accordion context. */
export function useAccordionContext() {
  const context = useContext(AccordionContext);
  if (!context) {
    throw new Error("Accordion compound components must be used within Accordion");
  }
  return context;
}

/** Context value shared by accordion item. */
export interface AccordionItemContextValue {
  /** Stable identifier matched against the Accordion value. */
  value: string;
  /** Whether accordion item is open. */
  isOpen: boolean;
  /** Disables the item: trigger is not focusable and not toggleable. */
  disabled: boolean;
  /** DOM id for trigger. */
  triggerId: string;
  /** DOM id for content. */
  contentId: string;
}

/** React context backing accordion item. */
export const AccordionItemContext = createContext<AccordionItemContextValue | undefined>(undefined);

/** Reads the accordion item context. */
export function useAccordionItemContext() {
  const context = useContext(AccordionItemContext);
  if (!context) {
    throw new Error("AccordionTrigger/AccordionContent must be used within AccordionItem");
  }
  return context;
}

"use client";

import type { ReactNode } from "react";
import { cn } from "@/lib/utils";
import { AccordionHeaderContext } from "./accordion-context";

/** Props for accordion header. */
export interface AccordionHeaderProps {
  /** Heading level wrapping the trigger. */
  as?: "h2" | "h3" | "h4" | "h5" | "h6";
  /** Typically an Accordion.Trigger. */
  children: ReactNode;
  /** Additional class names merged onto the rendered element. */
  className?: string;
}

/**
 * Optional explicit heading wrapper for trigger (h3 by default, configurable via as prop). Omit
 * it and AccordionTrigger supplies its own default heading.
 */
export function AccordionHeader({ as: Tag = "h3", children, className }: AccordionHeaderProps) {
  return (
    <AccordionHeaderContext value={true}>
      <Tag className={cn("m-0 font-normal", className)}>{children}</Tag>
    </AccordionHeaderContext>
  );
}

"use client";

import { type ReactNode, useId, useMemo } from "react";
import { cn } from "@/lib/utils";
import { AccordionItemContext, useAccordionContext } from "./accordion-context";

/** Props for accordion item. */
export interface AccordionItemProps {
  /** Stable identifier matched against the Accordion value. */
  value: string;
  /** Disables the item: trigger is not focusable and not toggleable. */
  disabled?: boolean;
  /** Header and Content children. */
  children: ReactNode;
  /** Additional class names merged onto the rendered element. */
  className?: string;
}

/** Wrapper for each collapsible section. */
export function AccordionItem({
  value,
  disabled = false,
  children,
  className,
}: AccordionItemProps) {
  const { value: openValues } = useAccordionContext();
  const isOpen = openValues.includes(value);
  const itemId = useId();
  const triggerId = `${itemId}-trigger`;
  const contentId = `${itemId}-content`;

  const contextValue = useMemo(
    () => ({ value, isOpen, disabled, triggerId, contentId }),
    [value, isOpen, disabled, triggerId, contentId],
  );

  return (
    <AccordionItemContext value={contextValue}>
      <div
        className={cn("py-2", className)}
        data-slot="accordion-item"
        data-state={isOpen ? "open" : "closed"}
        data-disabled={disabled || undefined}
      >
        {children}
      </div>
    </AccordionItemContext>
  );
}

"use client";

import { cva, type VariantProps } from "class-variance-authority";
import type { ComponentPropsWithRef, MouseEvent, ReactNode } from "react";
import { cn } from "@/lib/utils";
import { Chevron } from "../icons/chevron";
import {
  useAccordionContext,
  useAccordionHeaderPresent,
  useAccordionItemContext,
} from "./accordion-context";

/** Class variants for trigger. */
export const accordionTriggerVariants = cva(
  "flex w-full items-center gap-2 font-mono text-muted-foreground hover:text-foreground transition-colors cursor-pointer disabled:cursor-not-allowed disabled:hover:text-muted-foreground focus-visible:outline-2 focus-visible:outline-offset-2 focus-visible:outline-ring",
  {
    variants: {
      variant: {
        default: "text-sm",
        source: "text-xs mb-2",
      },
      disabled: {
        true: "opacity-50 cursor-not-allowed hover:text-muted-foreground",
        false: "",
      },
    },
    defaultVariants: { variant: "default", disabled: false },
  },
);

/** Props for accordion trigger variant. */
export type AccordionTriggerVariantProps = VariantProps<typeof accordionTriggerVariants>;

/** Props for accordion trigger. */
export interface AccordionTriggerProps
  extends Omit<ComponentPropsWithRef<"button">, "children">,
    Omit<VariantProps<typeof accordionTriggerVariants>, "disabled"> {
  /** Trigger label. */
  children: ReactNode;
  /** Custom handle element. Pass null to hide the chevron entirely. */
  handle?: ReactNode | null;
  /**
   * Heading level wrapping the trigger button (APG heading requirement). Ignored when the
   * trigger is already composed inside an AccordionHeader.
   */
  headingLevel?: "h2" | "h3" | "h4" | "h5" | "h6";
}

/**
 * Clickable button that toggles content. Wraps itself in a default h3 heading unless composed
 * inside AccordionHeader.
 */
export function AccordionTrigger({
  children,
  className,
  variant,
  handle,
  headingLevel: Heading = "h3",
  disabled: triggerDisabled,
  ref,
  onClick,
  ...props
}: AccordionTriggerProps) {
  const { onToggle, collapsible } = useAccordionContext();
  const { value, isOpen, disabled, triggerId, contentId } = useAccordionItemContext();
  const headerPresent = useAccordionHeaderPresent();

  const isAriaDisabled = !collapsible && isOpen;
  const isDisabled = disabled || !!triggerDisabled;
  const resolvedHandle = handle === undefined ? <Chevron open={isOpen} size="sm" /> : handle;
  const handleClick = (event: MouseEvent<HTMLButtonElement>) => {
    onClick?.(event);
    if (event.defaultPrevented) return;

    if (isDisabled || isAriaDisabled) {
      event.preventDefault();
      return;
    }

    onToggle(value);
  };

  const trigger = (
    <button
      {...props}
      ref={ref}
      type="button"
      id={triggerId}
      data-slot="accordion-trigger"
      data-state={isOpen ? "open" : "closed"}
      data-value={value}
      data-diffgazer-navigation-item="button"
      data-disabled={isDisabled ? "" : undefined}
      onClick={handleClick}
      disabled={isDisabled}
      aria-disabled={isAriaDisabled || disabled || undefined}
      aria-expanded={isOpen}
      aria-controls={contentId}
      className={cn(
        accordionTriggerVariants({ variant, disabled: isDisabled || isAriaDisabled }),
        className,
      )}
    >
      {resolvedHandle}
      {children}
    </button>
  );

  if (headerPresent) return trigger;

  return <Heading className="m-0 font-normal">{trigger}</Heading>;
}

"use client";

import type { ReactNode } from "react";
import { cn } from "@/lib/utils";
import { useAccordionItemContext } from "./accordion-context";

/** Props for accordion content. */
export interface AccordionContentProps {
  /** Collapsible body content. */
  children: ReactNode;
  /** Additional class names merged onto the rendered element. */
  className?: string;
  /**
   * Opt in to role="region" with aria-labelledby pointing at the trigger while the panel is
   * open. Off by default per the APG accordion pattern (region is listed as optional). Enable
   * for a small number of substantive panels (typically six or fewer); leave it off for many
   * short items to avoid landmark noise.
   */
  region?: boolean;
}

/** Collapsible body region. */
export function AccordionContent({ children, className, region = false }: AccordionContentProps) {
  const { isOpen, triggerId, contentId } = useAccordionItemContext();
  const exposesRegion = region && isOpen;

  return (
    <div
      className={cn(
        "grid transition-[grid-template-rows] duration-200 ease-out motion-reduce:transition-none",
        isOpen ? "grid-rows-[1fr]" : "grid-rows-[0fr]",
      )}
      aria-hidden={!isOpen || undefined}
      inert={!isOpen || undefined}
    >
      {/* biome-ignore lint/a11y/useAriaPropsSupportedByRole: role is conditionally "region" (Biome cannot resolve the ternary); aria-labelledby is applied only in the same branch and is valid for the region role. */}
      <div
        className={cn("overflow-hidden min-h-0 pt-2", className)}
        data-slot="accordion-content"
        data-state={isOpen ? "open" : "closed"}
        role={exposesRegion ? "region" : undefined}
        id={contentId}
        aria-labelledby={exposesRegion ? triggerId : undefined}
      >
        {children}
      </div>
    </div>
  );
}

"use client";

import {
  type KeyboardEvent as ReactKeyboardEvent,
  type ReactNode,
  type Ref,
  useCallback,
} from "react";
import {
  type UseControllableStateOptions,
  useControllableState,
} from "@/hooks/use-controllable-state";

/** Props for accordion in single-selection mode. */
export interface AccordionSingleProps {
  /**
   * Single allows one open item; multiple allows several open at once. Switches the
   * value/onChange/defaultValue shape from string to string[].
   */
  type?: "single";
  /** Controlled open value(s). string for single mode, string[] for multiple. */
  value?: string;
  /**
   * Fired when the open value(s) change. Receives the next value; in single non-collapsible
   * mode it never receives undefined.
   */
  onChange?: (value: string | null) => void;
  /** Initial open value(s) for uncontrolled mode. */
  defaultValue?: string;
  /** Single mode only. When false, the currently open item cannot be closed by clicking it. */
  collapsible?: boolean;
  /** AccordionItem children. */
  children: ReactNode;
  /** Additional class names merged onto the rendered element. */
  className?: string;
  /** Accessible name when no visible label is supplied. */
  "aria-label"?: string;
  /** ID of the element that labels this component. */
  "aria-labelledby"?: string;
  /** Ref forwarded to the underlying element. */
  ref?: Ref<HTMLDivElement>;
  /** Called when key down occurs. */
  onKeyDown?: (event: ReactKeyboardEvent) => void;
}

/** Props for accordion in multiple-selection mode. */
export interface AccordionMultipleProps {
  /**
   * Single allows one open item; multiple allows several open at once. Switches the
   * value/onChange/defaultValue shape from string to string[].
   */
  type: "multiple";
  /** Controlled open value(s). string for single mode, string[] for multiple. */
  value?: string[];
  /**
   * Fired when the open value(s) change. Receives the next value; in single non-collapsible
   * mode it never receives undefined.
   */
  onChange?: (value: string[]) => void;
  /** Initial open value(s) for uncontrolled mode. */
  defaultValue?: string[];
  /** AccordionItem children. */
  children: ReactNode;
  /** Additional class names merged onto the rendered element. */
  className?: string;
  /** Accessible name when no visible label is supplied. */
  "aria-label"?: string;
  /** ID of the element that labels this component. */
  "aria-labelledby"?: string;
  /** Ref forwarded to the underlying element. */
  ref?: Ref<HTMLDivElement>;
  /** Called when key down occurs. */
  onKeyDown?: (event: ReactKeyboardEvent) => void;
}

/** Props for accordion. */
export type AccordionProps = AccordionSingleProps | AccordionMultipleProps;

function normalizeStateOptions(props: AccordionProps): UseControllableStateOptions<string[]> {
  if (props.type === "multiple") {
    return {
      value: props.value,
      controlled: "value" in props,
      defaultValue: props.defaultValue ?? [],
      onChange: props.onChange,
    };
  }
  let value: string[] | undefined;
  if ("value" in props) {
    value = props.value === undefined ? [] : [props.value];
  }

  return {
    value,
    controlled: "value" in props,
    defaultValue: props.defaultValue !== undefined ? [props.defaultValue] : [],
    onChange: props.onChange ? (v: string[]) => props.onChange?.(v[0] ?? null) : undefined,
  };
}

function toggleSingle(prev: string[], value: string, collapsible: boolean): string[] {
  if (!prev.includes(value)) return [value];
  return collapsible ? [] : prev;
}

function toggleMultiple(prev: string[], value: string): string[] {
  return prev.includes(value) ? prev.filter((v) => v !== value) : [...prev, value];
}

/** Provides accordion state behavior. */
export function useAccordionState(props: AccordionProps) {
  const isSingle = props.type !== "multiple";
  const collapsible = props.type !== "multiple" ? (props.collapsible ?? true) : true;

  const [openValues, setOpenValues] = useControllableState(normalizeStateOptions(props));

  const onToggle = useCallback(
    (itemValue: string) => {
      setOpenValues((prev) =>
        isSingle ? toggleSingle(prev, itemValue, collapsible) : toggleMultiple(prev, itemValue),
      );
    },
    [collapsible, isSingle, setOpenValues],
  );

  return { openValues, onToggle, collapsible };
}
